"""sample_tests.py — a text fixture of test code (not collected by pytest;
it lives under loops/test-naming-contract/seed/ and is read by the checker
as source text/AST, never executed).

Fixed: 'check_addition' renamed to 'test_addition' so a pytest-style runner
actually collects it.
"""


def add(a, b):
    return a + b


def subtract(a, b):
    return a - b


def test_subtraction():
    assert subtract(5, 3) == 2


def test_addition():
    assert add(2, 2) == 4


class TestMath:
    def test_add_negative(self):
        assert add(-1, -1) == -2
